// import { createMemoryHistory, createRouter } from 'vue-router'
import { createWebHistory, createRouter } from 'vue-router'

import SiprComponent from './components/SiprComponent.vue'
import HomeView from './components/HomeView.vue'
import TheoryView from './components/TheoryView.vue'
import AboutView from './components/AboutView.vue'
import axios from 'axios';

const backendURL = 'http://qerev.freeddns.org:8000'
// const backendURL = 'http://chestnut.jesuitas.vpn:8000'
axios.defaults.xsrfHeaderName = "X-CSRFTOKEN";
axios.defaults.xsrfCookieName = "csrftoken";
axios.defaults.withCredentials = true;
axios.get(backendURL, {withCredentials: true});

const routes = [
  { path: '/', component: HomeView },
  { path: '/theory', component: TheoryView },
  { path: '/about', component: AboutView },
  { path: '/passage/:passage', component: SiprComponent, props: { backendURL: backendURL }, },
]

const router = createRouter({
  // history: createMemoryHistory(),
  history: createWebHistory(),
  routes,
})

export default router
